## ms Integration Points

### 1. Pre-Commit Hook for Skills

Validate skill code snippets before publishing:

```rust
impl SkillValidator {
    async fn validate_code_snippets(&self, skill: &SkillSpec) -> Result<ValidationResult> {
        // Extract code blocks from skill
        let code_blocks = skill.extract_code_blocks();

        // Write to temp files
        let temp_files = self.write_temp_files(&code_blocks)?;

        // Run UBS
        let ubs_result = self.ubs.check(&temp_files).await?;

        if ubs_result.exit_code != 0 {
            return Err(ValidationError::UbsFindings(ubs_result.findings));
        }

        Ok(ValidationResult::Clean)
    }
}
```

### 2. Pattern Extraction Quality Gate

Don't extract patterns from code with UBS findings:

```rust
impl PatternExtractor {
    async fn extract(&self, session: &Session) -> Result<Vec<Pattern>> {
        let code_blocks = session.extract_code_changes();

        // Run UBS on extracted code
        let ubs_result = self.ubs.check_code(&code_blocks).await?;

        // Skip patterns from code with critical findings
        if ubs_result.has_critical_findings() {
            log::warn!("Skipping patterns from code with UBS findings");
            return Ok(vec![]);
        }

        // Continue extraction
        self.extract_patterns(session)
    }
}
```

